    private static final int MAX_PAYLOAD_SIZE = 50 * 1024 * 1024;
    private static final ExecutorService executorService = Executors.newFixedThreadPool(10);
    private static final Map<String, ImportStatus> importStatusMap = new ConcurrentHashMap<>();

    @WebMethod(operationName = "importData")
    public String importData(@WebParam(name = "xmlData") String xmlData) {
        try {
            if (xmlData == null || xmlData.isEmpty()) {
                return createErrorResponse("Empty XML data received");
            }

            if (xmlData.length() > MAX_PAYLOAD_SIZE) {
                return createErrorResponse("Payload size exceeds maximum limit");
            }

            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new InputSource(new StringReader(xmlData)));
            document.getDocumentElement().normalize();

            String importId = UUID.randomUUID().toString();
            ImportStatus status = new ImportStatus(importId, "PROCESSING");
            importStatusMap.put(importId, status);

            executorService.submit(() -> processDocument(document, importId));

            return createSuccessResponse(importId, "Data import initiated successfully");

        } catch (Exception e) {
            return createErrorResponse("Error processing XML: " + e.getMessage());
        }
    }

